body.script:
//
(function(){
'use strict';

/* ══ CONFIG — CHANGE THIS ══ */
var CPA = 'https://YOUR-CPA-LOCKER-LINK-HERE.com';

/* ══ TMDB ══ */
var IM  = 'https://image.tmdb.org/t/p/w500';
var IMB = 'https://image.tmdb.org/t/p/w1280';

/* ══ DB ══ */
var XDB = [
  {id:1, t:"Dune: Part Two",                     y:"2024", s:8.5, g:"Sci-Fi",    tp:"Movie",  b:"IMAX",   p:"/cdqLnri3NEGcmfnqwk2TSIYtddg.jpg", bd:"/xOMo8BRK7PfcJv9JCnx7s5hj0ox.jpg", c:"#0c0e28,#1a0a14", d:"Paul Atreides unites with the Fremen on a warpath of revenge against the conspirators who destroyed his family.", ca:["T. Chalamet","Z. Depp","F. Ferguson"]},
  {id:2, t:"The Batman",                          y:"2022", s:7.8, g:"Action",    tp:"Movie",  b:"HD",     p:"/74xTEgt7R36Fpooo50r9T25onhq.jpg",  bd:"/5P8SmMzik7q9sMH7aN3L76bDrDm.jpg",  c:"#070710,#0d0d1e", d:"A sadistic serial killer murders key political figures in Gotham, forcing Batman to investigate the city's hidden corruption.", ca:["R. Pattinson","Z. Kravitz","P. Dano"]},
  {id:3, t:"Inside Out 2",                        y:"2024", s:7.6, g:"Animation", tp:"Movie",  b:"HD",     p:"/vpnVM9B6NMmQpWeZvzLvDESb2QY.jpg",  bd:"/4YZgsHLBBceUtXkJ55MuBWhT5ia.jpg",  c:"#0a1628,#1a0a2e", d:"Follow Riley in her teenage years as a new emotion — Anxiety — joins her existing emotions.", ca:["A. Poehler","M. Smith","K. Minogue"]},
  {id:4, t:"Mission Impossible Dead Reckoning",   y:"2023", s:7.7, g:"Action",    tp:"Movie",  b:"HD",     p:"/NNxYkU70HPurnNCSiCjYAmacwm.jpg",   bd:"/1CCB1OcIVOtDxMBOy5odiCqFhCl.jpg",  c:"#0d1b0a,#0a1400", d:"Ethan Hunt and his IMF team must track down a terrifying new weapon that threatens all of humanity.", ca:["T. Cruise","H. Atwell","S. Pegg"]},
  {id:5, t:"Avatar The Way of Water",             y:"2022", s:7.6, g:"Sci-Fi",    tp:"Movie",  b:"IMAX",   p:"/t6HIqrRAclMCA60NsSmeqe9RmNV.jpg",  bd:"/s16H6tpK2utvwpaezv13APeeqMd.jpg",  c:"#0a1a1a,#001a10", d:"Jake Sully and Neytiri must leave their home and explore the regions of Pandora to protect their family.", ca:["S. Worthington","Z. Saldana","S. Lang"]},
  {id:6, t:"Gladiator II",                        y:"2024", s:6.5, g:"Action",    tp:"Movie",  b:"HD",     p:"/2cxhvwyE0RYfnm7tCI4BPwWDFIf.jpg",  bd:"/euYIwmwkmz95mnXvufEJIE6nCh7.jpg",  c:"#1a0a00,#120800", d:"Lucius is forced into the Colosseum and must look to his past to return glory to Rome.", ca:["P. Mescal","D. Washington","P. Pascal"]},
  {id:7, t:"The Last of Us",                      y:"2023", s:8.8, g:"Drama",     tp:"Series", b:"SERIES", p:"/uKvVjHNqB5VmOrdxqAt2F7J78ED.jpg",  bd:"/9PqD3wSIjntyJDBzMNuxuKHuMPa.jpg",  c:"#1a0a0a,#120808", d:"Joel smuggles Ellie out of a quarantine zone in this brutal, heartbreaking post-apocalyptic journey.", ca:["P. Pascal","B. Ramsey","G. Johnson"]},
  {id:8, t:"House of the Dragon",                 y:"2022", s:8.5, g:"Fantasy",   tp:"Series", b:"SERIES", p:"/z2yahl2uefxDCl0nogcRBstwruJ.jpg",  bd:"/etj8E2o0Bud0HkONVQPjyCkIvpv.jpg",  c:"#1a0d00,#130900", d:"The story of House Targaryen set 200 years before Game of Thrones.", ca:["E. D'Arcy","M. Alcock","O. Cooke"]},
  {id:9, t:"Squid Game",                          y:"2021", s:8.0, g:"Thriller",  tp:"Series", b:"SERIES", p:"/dDlEmu3EZ0Pgg93K2SVNLCjCSvE.jpg",  bd:"/qw3J9cNeLioOLoR68WX7z79aCdK.jpg",  c:"#00121a,#000d12", d:"Cash-strapped players accept a strange invitation to compete in children's games with deadly stakes.", ca:["L. Jung-jae","L. Byung-hun","Y. Ji-hye"]},
  {id:10,t:"Wednesday",                           y:"2022", s:8.1, g:"Horror",    tp:"Series", b:"SERIES", p:"/9PFonBhy4cQy7Jz20NpMygczOkv.jpg",  bd:"/iHSwvRVsRyxpX7FE7GbviaDvgGZ.jpg",  c:"#0d000d,#080008", d:"Wednesday Addams masters her psychic ability while thwarting a monster killing spree.", ca:["J. Ortega","E. Ricci","C. Laurie"]},
  {id:11,t:"Severance",                           y:"2022", s:8.7, g:"Sci-Fi",    tp:"Series", b:"SERIES", p:"/lHb0Lym0BjgXhRBRodRYP9fcE2h.jpg",  bd:"/bPBaHFhYKHaVBZBY9BPTCQHQWyN.jpg",  c:"#0a0f1a,#070b14", d:"Mark leads a team whose memories are surgically divided between work and personal life.", ca:["A. Scott","B. Turturro","P. Arquette"]},
  {id:12,t:"The Bear",                            y:"2022", s:8.6, g:"Drama",     tp:"Series", b:"SERIES", p:"/qGf3b0BFR8Uy6MXnPNkJy7UMtyM.jpg",  bd:"/4JQTO2k4Zm0RDkKfpWYLT0iEUh8.jpg",  c:"#0f0a00,#100b00", d:"A young chef returns to Chicago to run his family sandwich shop, grappling with grief and ambition.", ca:["J. Allen","A. Taylor-Joy","O. Coleman"]},
  {id:13,t:"Oppenheimer",                         y:"2023", s:8.3, g:"Drama",     tp:"Movie",  b:"HD",     p:"/8Gxv8gSFCU0XGDykEGv7zR1n2ua.jpg",  bd:"/rLb2cwF3Pazuxaj0sRXQ037tGI1.jpg",  c:"#1a0a00,#0d0500", d:"The story of J. Robert Oppenheimer and his role in developing the atomic bomb.", ca:["C. Murphy","E. Blunt","R. Downey Jr."]},
  {id:14,t:"Poor Things",                         y:"2023", s:7.8, g:"Drama",     tp:"Movie",  b:"HD",     p:"/kCGlIMHnOm8JPXEleHCLh1NTVG0.jpg",  bd:"/jXJxMcVoEuXzym3vFnjqDW4ifo6.jpg",  c:"#0f0028,#0a001a", d:"Bella Baxter, brought back to life by an unorthodox scientist, embarks on a wild Victorian odyssey.", ca:["E. Stone","W. Dafoe","M. Ruffalo"]},
  {id:15,t:"Fast X",                              y:"2023", s:5.9, g:"Action",    tp:"Movie",  b:"HD",     p:"/fiVW06jE7z9F3NZTSt8q4eCHjeX.jpg",  bd:"/rqbCbjoh9A74Z4htRBnrGdmzMR6.jpg",  c:"#1a0f0a,#120a06", d:"Dom Toretto and his family are targeted by the vengeful son of drug kingpin Hernan Reyes.", ca:["V. Diesel","M. Rodriguez","J. Momoa"]},
];

/* ══ HELPERS ══ */
function ini(t){return t.split(' ').map(function(w){return w[0]}).join('').slice(0,2).toUpperCase()}
function bcls(b){return b==='SERIES'?'bs':b==='IMAX'?'bim':b==='NEW'?'bn':'bh'}

/* ══ POSTER LOAD — background-image via JS: zero CORS on Blogger ══ */
function loadBg(el, url, showCls) {
  if (!el || !url) return;
  var img = new Image();
  img.onload = function() {
    el.style.backgroundImage = 'url(' + url + ')';
    if (showCls) el.classList.add(showCls);
  };
  img.src = url;
}

/* ══ WATCHLIST ══ */
function gwl(){try{return JSON.parse(localStorage.getItem('cpwl5')||'[]')}catch(e){return[]}}
function swl(w){try{localStorage.setItem('cpwl5',JSON.stringify(w))}catch(e){}}
function inwl(id){return gwl().indexOf(id) > -1}

function toggleWL(id) {
  var item = XDB[id];
  if (!item) return;
  var wl = gwl(), i = wl.indexOf(item.id);
  if (i > -1) { wl.splice(i,1); xtoast('Removed from Watchlist'); }
  else { wl.push(item.id); xtoast('Added to Watchlist ✓'); }
  swl(wl);
  // update all wl buttons for this item
  document.querySelectorAll('[data-action="save"][data-idx="' + id + '"]').forEach(function(btn){
    btn.textContent = inwl(item.id) ? '✓ Saved' : '♥ Save';
    btn.classList.toggle('sv', inwl(item.id));
  });
  document.querySelectorAll('.cbwl[data-idx="' + id + '"]').forEach(function(btn){
    btn.textContent = inwl(item.id) ? '✓' : '♥';
    btn.classList.toggle('sv', inwl(item.id));
  });
  if (document.getElementById('xpg-wl').classList.contains('on')) rwl();
}

/* ══ CARD HTML — no inline onclick, use data-* attributes ══ */
function card(item, idx) {
  var sv = inwl(item.id), bc = bcls(item.b), col = item.c || '#0c0e28,#1a0a0e';
  var dbxIdx = item.id - 1;
  return '<div class="xcard" data-idx="' + dbxIdx + '" style="animation-delay:' + (idx * .06) + 's">'
    + '<div class="xct" data-action="info" data-idx="' + dbxIdx + '">'
    + '<div class="xct-bg" data-poster="' + IM + item.p + '" style="background:linear-gradient(135deg,' + col + ')"></div>'
    + '<div class="xct-fb">' + ini(item.t) + '</div>'
    + '<div class="xveil"><div class="xplay"><svg width="11" height="11" viewBox="0 0 16 16" fill="white"><polygon points="3,1 15,8 3,15"/></svg></div></div>'
    + '<div class="xbdg ' + bc + '">' + item.b + '</div>'
    + '<div class="xrk">' + ('0' + (idx+1)).slice(-2) + '</div>'
    + '</div>'
    + '<div class="xcb">'
    + '<div class="xcn">' + item.t + '</div>'
    + '<div class="xcm"><span class="xcsc">★ ' + item.s + '</span><span>' + item.y + '</span><span>' + item.g + '</span></div>'
    + '<div class="xcbtns">'
    + '<button class="cbw" data-action="watch" data-idx="' + dbxIdx + '">&#9654; Watch</button>'
    + '<button class="cbwl ' + (sv?'sv':'') + '" data-action="save" data-idx="' + dbxIdx + '">' + (sv?'✓':'♥') + '</button>'
    + '<button class="cbtr" data-action="trail" data-idx="' + dbxIdx + '">&#9655;</button>'
    + '</div></div></div>';
}

/* ══ FEATURED CARD ══ */
function featCard(item) {
  var col = item.c || '#0c0e28,#1a0a0e';
  var dbxIdx = item.id - 1;
  return '<div class="xfc">'
    + '<div class="xft" data-action="info" data-idx="' + dbxIdx + '">'
    + '<span class="xft-tx">' + ini(item.t) + '</span>'
    + '<div class="xft-bg" data-poster="' + IM + item.p + '" style="background:linear-gradient(135deg,' + col + ')"></div>'
    + '<div class="xft-ov"></div>'
    + '</div>'
    + '<div class="xfbd">'
    + '<div style="display:flex;gap:.38rem;margin-bottom:.38rem;flex-wrap:wrap;align-items:center">'
    + '<span class="xpill" style="font-size:.64rem">' + item.g + '</span>'
    + '<span class="xpill" style="font-size:.64rem">' + item.y + '</span>'
    + '<span style="color:var(--gold);font-size:.7rem;font-weight:700">★ ' + item.s + '</span>'
    + '</div>'
    + '<div class="xftt">' + item.t + '</div>'
    + '<div class="xfd">' + item.d + '</div>'
    + '<div class="xfbtns">'
    + '<button class="bw" style="padding:7px 11px;font-size:.72rem" data-action="watch" data-idx="' + dbxIdx + '">&#9654; Watch</button>'
    + '<button class="bi" style="padding:7px 10px;font-size:.72rem" data-action="info" data-idx="' + dbxIdx + '">ⓘ Info</button>'
    + '<button class="bwl" style="padding:7px 8px;font-size:.72rem" data-action="save" data-idx="' + dbxIdx + '">♥</button>'
    + '</div></div></div>';
}

/* ══ RENDER GRID + LOAD POSTERS ══ */
function rg(elId, data, feat) {
  var el = document.getElementById(elId);
  if (!el) return;
  el.innerHTML = data.map(function(m, i){ return feat ? featCard(m) : card(m, i) }).join('');
  // Load all posters — backgroundImage trick, no CORS
  el.querySelectorAll('[data-poster]').forEach(function(div) {
    loadBg(div, div.getAttribute('data-poster'), 'show');
  });
}

/* ══ PAGES ══ */
var PGS = ['home','movies','series','action','scifi','drama','wl','search','detail'];
var GRID_MAP = {movies:'xmovg',series:'xserg',action:'xactg',scifi:'xscig',drama:'xdrag'};
var DATA_MAP = {
  movies: function(){return XDB.filter(function(d){return d.tp==='Movie'})},
  series: function(){return XDB.filter(function(d){return d.tp==='Series'})},
  action: function(){return XDB.filter(function(d){return d.g==='Action'})},
  scifi:  function(){return XDB.filter(function(d){return d.g==='Sci-Fi'})},
  drama:  function(){return XDB.filter(function(d){return d.g==='Drama'})}
};

function xgo(name) {
  PGS.forEach(function(p) {
    var el = document.getElementById('xpg-' + p); if (el) el.classList.toggle('on', p === name);
    var dt = document.getElementById('xt-' + p);  if (dt) dt.classList.toggle('on', p === name);
    var mt = document.getElementById('xm-' + p);  if (mt) mt.classList.toggle('on', p === name);
  });
  window.scrollTo({top:0, behavior:'smooth'});
  if (name === 'home') ihome();
  else if (GRID_MAP[name]) rg(GRID_MAP[name], DATA_MAP[name](), false);
  else if (name === 'wl') rwl();
}

/* ══ HOME ══ */
function ihome() {
  var h = XDB[0];
  // Hero backdrop
  var bdEl = document.getElementById('hebd');
  if (bdEl) loadBg(bdEl, IMB + h.bd, null);
  setTimeout(function(){ if(bdEl) bdEl.style.opacity = '1'; }, 100);

  document.getElementById('hett').innerHTML = h.t + '<br><span class="heghost">Free HD Stream</span>';
  document.getElementById('heds').textContent = h.d;
  document.getElementById('hesc').textContent = '★ ' + h.s;
  document.getElementById('hegen').textContent = h.g;
  var hw = document.getElementById('hewl');
  if (hw) { hw.textContent = inwl(h.id) ? '✓ Saved' : '♥ Save'; hw.classList.toggle('sv', inwl(h.id)); }

  rg('xtrend',   XDB.slice(0, 5),  false);
  rg('xserhome', XDB.filter(function(m){ return m.tp==='Series' }).slice(0,5), false);
  rg('xnew',     XDB.filter(function(m){ return m.tp==='Movie'  }).slice(0,5), false);
  rg('xpicks',   [XDB[0], XDB[6], XDB[8]], true);
}

/* ══ FILTER ══ */
function applyFilter(btn, f, pg) {
  var row = btn.closest('.xfrow');
  if (row) row.querySelectorAll('.xfb').forEach(function(b){ b.classList.remove('on') });
  btn.classList.add('on');
  var data = DATA_MAP[pg] ? DATA_MAP[pg]().slice() : XDB.slice();
  if (f === 'top') data.sort(function(a,b){ return b.s - a.s });
  else if (f === '2024') data = data.filter(function(d){ return d.y === '2024' });
  else if (f === '2023') data = data.filter(function(d){ return d.y === '2023' });
  else if (['Drama','Thriller','Fantasy','Action','Sci-Fi'].indexOf(f) > -1) data = data.filter(function(d){ return d.g === f });
  rg(GRID_MAP[pg], data, false);
}

/* ══ DETAIL ══ */
function showDetail(idx) {
  var item = XDB[idx];
  if (!item) return;
  var col = item.c || '#0c0e28,#1a0a0e', sv = inwl(item.id), bc = bcls(item.b);
  var cc = ['#0c0e28','#1a0a0e','#0a1628','#0d1b0a','#0a1a1a'];
  // backdrop
  var bg = document.getElementById('xdbg');
  bg.style.background = 'linear-gradient(135deg,' + col + ')';
  if (item.bd) loadBg(bg, IMB + item.bd, null);
  // side poster
  var pp = document.getElementById('xdposter');
  pp.style.backgroundImage = 'none';
  if (item.p) loadBg(pp, IM + item.p, null);
  // content
  var dIdx = item.id - 1;
  document.getElementById('xdin').innerHTML =
    '<div style="display:flex;gap:.38rem;margin-bottom:.8rem;flex-wrap:wrap;align-items:center">'
    + '<span class="xbdg ' + bc + '" style="position:relative;top:0;left:0">' + item.b + '</span>'
    + '<span class="xpill">' + item.tp + '</span><span class="xpill">' + item.y + '</span>'
    + '<span style="color:var(--gold);font-weight:700;font-size:.78rem">★ ' + item.s + '</span>'
    + '</div>'
    + '<h1 class="xdtt">' + item.t + '</h1>'
    + '<p class="xddes">' + item.d + '</p>'
    + '<div class="xdtags"><span class="xdtag">' + item.g + '</span><span class="xdtag">' + item.y + '</span><span class="xdtag">4K HD</span><span class="xdtag">Free Stream</span></div>'
    + '<div class="xdact">'
    + '<button class="bw" data-action="watch" data-idx="' + dIdx + '"><svg width="11" height="11" viewBox="0 0 16 16" fill="white"><polygon points="3,1 15,8 3,15"/></svg> Watch Free</button>'
    + '<button class="btr" data-action="trail" data-idx="' + dIdx + '">&#9655; Trailer</button>'
    + '<button class="bwl ' + (sv?'sv':'') + '" data-action="save" data-idx="' + dIdx + '">' + (sv?'✓ Saved':'♥ Save') + '</button>'
    + '<button class="bsh" data-action="share" data-idx="' + dIdx + '">&#8679; Share</button>'
    + '</div>';
  document.getElementById('xdcast').innerHTML = '<div class="xclbl">CAST</div><div class="xcrw">'
    + (item.ca||[]).map(function(n,i){
        return '<div><div class="xcav" style="background:linear-gradient(135deg,' + cc[i%cc.length] + ',#10121e)">' + n.slice(0,2).toUpperCase() + '</div><div class="xcnm">' + n + '</div></div>';
      }).join('') + '</div>';
  var sim = XDB.filter(function(m){ return m.id!==item.id && (m.g===item.g||m.tp===item.tp) }).slice(0,4);
  rg('xdmore', sim, false);
  xgo('detail');
}

/* ══ WATCHLIST PAGE ══ */
function rwl() {
  var items = XDB.filter(function(d){ return inwl(d.id) });
  rg('xwlg', items, false);
  document.getElementById('xwle').style.display = items.length ? 'none' : 'block';
}

/* ══ SEARCH ══ */
function doSearch(q) {
  document.getElementById('cpnq').value = q;
  document.getElementById('xsi').value = q;
  if (!document.getElementById('xpg-search').classList.contains('on')) xgo('search');
  var res = q.length > 1 ? XDB.filter(function(m){
    return m.t.toLowerCase().indexOf(q.toLowerCase()) > -1 || m.g.toLowerCase().indexOf(q.toLowerCase()) > -1;
  }) : [];
  document.getElementById('xslbl').textContent = q.length > 1
    ? res.length + ' result' + (res.length !== 1 ? 's' : '') + ' for "' + q + '"'
    : 'Type to discover titles...';
  rg('xsg', res, false);
}

/* ══ LOCKER ══ */
function openLocker(title) {
  document.getElementById('xlkname').textContent = title;
  document.getElementById('xlkbg').classList.add('on');
}
function closeLocker() { document.getElementById('xlkbg').classList.remove('on') }

/* ══ TOAST ══ */
function xtoast(msg) {
  var t = document.getElementById('xtoast');
  t.textContent = msg; t.classList.add('on');
  clearTimeout(t._t); t._t = setTimeout(function(){ t.classList.remove('on') }, 2400);
}

/* ══ SHARE ══ */
function doShare(title) {
  if (navigator.share) { navigator.share({title:'CinePulse – '+title, url:window.location.href}); }
  else { try{navigator.clipboard.writeText(window.location.href); xtoast('Link copied!');}catch(e){xtoast('Copy URL from browser bar');} }
}

/* ══════════════════════════════════════════
   EVENT DELEGATION — one listener handles ALL clicks
   No inline onclick needed → works in Blogger
══════════════════════════════════════════ */
document.addEventListener('click', function(e) {
  var el = e.target;

  // walk up to find the element with data-action or data-go
  while (el && el !== document.body) {

    // Navigation: data-go
    var pg = el.getAttribute('data-go');
    if (pg) { xgo(pg); return; }

    // Filter buttons
    var filter = el.getAttribute('data-filter');
    var filterPg = el.getAttribute('data-pg');
    if (filter && filterPg) { applyFilter(el, filter, filterPg); return; }

    // Actions: data-action + data-idx
    var action = el.getAttribute('data-action');
    var idx = el.getAttribute('data-idx');
    if (action !== null && idx !== null) {
      var i = parseInt(idx, 10);
      var item = XDB[i];
      if (!item) return;
      if (action === 'watch') { openLocker(item.t); return; }
      if (action === 'info')  { showDetail(i); return; }
      if (action === 'save')  { toggleWL(i); return; }
      if (action === 'trail') { window.open('https://www.youtube.com/results?search_query=' + encodeURIComponent(item.t + ' official trailer'), '_blank'); return; }
      if (action === 'share') { doShare(item.t); return; }
    }

    // Locker close button
    if (el.id === 'xlkclose') { closeLocker(); return; }
    // Locker background click
    if (el.id === 'xlkbg') { closeLocker(); return; }
    // CPA unlock button
    if (el.id === 'xcpabtn') { window.open(CPA, '_blank'); return; }

    el = el.parentElement;
  }
});

/* ══ SEARCH INPUTS ══ */
document.getElementById('cpnq').addEventListener('input', function(){ doSearch(this.value) });
document.getElementById('cpnq').addEventListener('focus', function(){ xgo('search') });
document.getElementById('xsi').addEventListener('input', function(){ doSearch(this.value) });

/* ══ VISITOR COUNT ══ */
document.getElementById('cpvis').textContent = '👁 ' + (11800 + Math.floor(Math.random()*500)).toLocaleString() + ' watching now';

/* ══ INIT ══ */
ihome();

//
